1148	async function openSkillDetail(name) {
1149	  let d;
1150	  try {
1151	    d = await Promise.all(TOOLS.map((to) =>
1152	      api('/skills/diff?name=' + encodeURIComponent(name) + '&to=' + encodeURIComponent(to)).then((x) => ({ to, ...x }))
1153	    ));
1154	  } catch (e) { toast('상세를 불러오지 못했습니다: ' + e.message); return; }
1155	  const allLosses = [];
1156	  const cards = d.map((x) => {
1157	    (x.losses || []).forEach((l) => allLosses.push(`[${x.to}] ${l}`));
1158	    const changes = !x.canonicalExists ? '없음' : (x.hasChanges ? '변경 있음' : '동일');
1159	    return `<div class="ov-card">
1160	      <div class="ov-head"><span class="tool-dot" style="background:${TOOL_COLOR[x.to]}"></span>${x.to}</div>
