1162	      <div class="ov-kv">상태: ${changes}</div>
1163	      <button class="btn btn-secondary btn-sm" data-skill-diff-name="${esc(name)}" data-skill-diff-to="${x.to}">diff 보기</button>
1164	      <button class="btn btn-secondary btn-sm" data-skill-apply="${esc(name)}" data-skill-apply-to="${x.to}" ${x.canonicalExists ? '' : 'disabled'}>적용</button>
1165	    </div>`;
1166	  }).join('');
1167	  const anyCanon = d.some((x) => x.canonicalExists);
1168	  openPanel({
1169	    title: name,
1170	    meta: '<span class="kv"><b>스킬 상세</b></span>',
1171	    bodyHtml: lossBanner(allLosses) + '<div class="sub-label">모델별 미리보기/적용</div><div class="overlay-grid">' + cards + '</div><div id="skill-apply-all-result"></div><div id="skill-inline-diff"></div>',
1172	    footHtml: `<button class="btn btn-primary" data-sync-open="skill" data-sync-name="${esc(name)}">동기화</button><button class="btn btn-secondary" data-skill-apply-all="${esc(name)}" ${anyCanon ? '' : 'disabled'}>중앙 저장소 → 세 모델</button><button class="btn btn-ghost" data-view-open="skill" data-view-name="${esc(name)}" data-view-scope="${esc(mxScopeOf('skill', name))}">내용 보기</button><button class="btn btn-ghost" data-tag-kind="skill" data-tag-id="${esc(name)}">태그 수정</button><button class="btn btn-ghost" id="panel-cancel">닫기</button>`,
1173	  });
1174	}

