// [이 모델을 기준으로 동기화] → apply:false 로 diff 요약을 받아 모달에 표시.
async function openInstrSync(base) {
  currentInstrSync = { base };
  currentPullTool = null; currentAgentPull = null; currentSkillPull = null; currentSync = null; currentStoreApply = null;
  $('#instr-sync-title').textContent = `${base} 기준으로 동기화`;
  $('#instr-sync-body').innerHTML = '<div class="skel">변경 요약을 계산하는 중…</div>';
  $('#instr-sync-confirm').disabled = true;
  $('#instr-sync-confirm').hidden = false;
  $('#instr-sync-cancel').textContent = '취소';
  $('#instr-sync-modal').hidden = false;
  let d;
  try { d = await api('/instr/sync', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ base, apply: false }) }); }
  catch (e) { $('#instr-sync-body').innerHTML = `<div class="empty-state">요약을 불러오지 못했습니다: ${esc(e.message)}</div>`; return; }
  renderInstrSyncPreview(d);
}

function renderInstrSyncPreview(d) {
  const targets = d.targets || [];
  const rows = targets.map((t) => {
    let detail;
    if (t.willCreate) detail = '<span class="badge ok">새로 생성</span>';
    else if (!t.hasChanges) detail = '<span class="badge muted">이미 같음 — 그대로</span>';
    else detail = `<span class="badge warn">바뀜</span><span class="instr-sync-nums">+${t.added} / -${t.removed}줄</span>`;
    return `<div class="sync-result-row">
      <span class="tool-dot" style="background:${TOOL_COLOR[t.to]}"></span>
      <span class="tool-name">${esc(t.to)}</span>
      ${detail}
    </div>`;
  }).join('');
  const anyChange = targets.some((t) => t.willCreate || t.hasChanges);
  const lead = anyChange
    ? `<b>${esc(d.base)}</b> 내용을 기준으로 다른 모델을 맞춥니다. 덮어쓰기 전에 자동 백업합니다.`
    : `다른 모델이 이미 <b>${esc(d.base)}</b>와 같습니다 — 바뀌는 파일이 없습니다.`;
  $('#instr-sync-body').innerHTML =
    `<div class="sync-lead">${lead}</div>
     <div class="sync-base-label">모델별 변경 요약</div>
     ${rows || '<div class="muted" style="padding:10px">맞출 대상 모델이 없습니다.</div>'}`;
  // 확인 버튼: 바뀔 게 없어도 실행은 허용(멱등 — 안전). 텍스트만 상황에 맞춘다.
  $('#instr-sync-confirm').disabled = false;
  $('#instr-sync-confirm').textContent = anyChange ? '이대로 동기화' : '동기화 실행';
}

// 확인 클릭 → apply:true. 409(PI)는 기존 PI 모달 패턴 재사용.
async function runInstrSync(piAck) {
  if (!currentInstrSync) return;
  const { base } = currentInstrSync;
  $('#instr-sync-confirm').disabled = true;
  const res = await fetch('/instr/sync', { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ base, apply: true, piAck }) });
  // #9 패턴: 409 전에 버튼 복구(PI 취소 후 재실행 가능).
  if (res.status === 409) { $('#instr-sync-confirm').disabled = false; showPiModal(await res.json()); return; }
  if (!res.ok) { $('#instr-sync-confirm').disabled = false; toast('동기화하지 못했습니다: ' + (await errMsg(res))); return; }
  const r = await res.json();
  $('#pi-modal').hidden = true;
  // PI 게이트에서 제외 선택 → 기준을 저장하지 않아 동기화 중단.
  if (r.pulled && r.pulled.imported === false) {
    $('#instr-sync-confirm').disabled = false;
    toast('제외됨 — 동기화하지 않았습니다');
    return;
  }
  const results = r.results || [];
  const okN = results.filter((x) => x.applied).length;
  const failN = results.filter((x) => x.applied === false).length;
  const backups = results.filter((x) => x.applied && x.backupPath).length;
  toast(`✓ 동기화 완료 · ${okN}개 모델${failN ? ` · 실패 ${failN}` : ''}${backups ? ` · 백업 ${backups}건` : ''}`);
  closeInstrSyncModal();
  loadInstructions();
  loadSyncLog();
}

function closeInstrSyncModal() {
  $('#instr-sync-modal').hidden = true;
  currentInstrSync = null;
}

