async function openSkillDetail(name) {
  let d;
  try {
    d = await Promise.all(TOOLS.map((to) =>
      api('/skills/diff?name=' + encodeURIComponent(name) + '&to=' + encodeURIComponent(to)).then((x) => ({ to, ...x }))
    ));
  } catch (e) { toast('상세를 불러오지 못했습니다: ' + e.message); return; }
  const allLosses = [];
  const cards = d.map((x) => {
    (x.losses || []).forEach((l) => allLosses.push(`[${x.to}] ${l}`));
    const changes = !x.canonicalExists ? '없음' : (x.hasChanges ? '변경 있음' : '동일');
    return `<div class="ov-card">
      <div class="ov-head"><span class="tool-dot" style="background:${TOOL_COLOR[x.to]}"></span>${x.to}</div>
      <div class="ov-kv"><b>대상</b> <code>${esc((x.targetPath || '').split('/').slice(-2).join('/'))}</code></div>
      <div class="ov-kv">상태: ${changes}</div>
      <button class="btn btn-secondary btn-sm" data-skill-diff-name="${esc(name)}" data-skill-diff-to="${x.to}">diff 보기</button>
      <button class="btn btn-secondary btn-sm" data-skill-apply="${esc(name)}" data-skill-apply-to="${x.to}" ${x.canonicalExists ? '' : 'disabled'}>적용</button>
    </div>`;
  }).join('');
  const anyCanon = d.some((x) => x.canonicalExists);
  openPanel({
    title: name,
    meta: '<span class="kv"><b>스킬 상세</b></span>',
    bodyHtml: lossBanner(allLosses) + '<div class="sub-label">모델별 미리보기/적용</div><div class="overlay-grid">' + cards + '</div><div id="skill-apply-all-result"></div><div id="skill-inline-diff"></div>',
    footHtml: `<button class="btn btn-primary" data-sync-open="skill" data-sync-name="${esc(name)}">동기화</button><button class="btn btn-secondary" data-skill-apply-all="${esc(name)}" ${anyCanon ? '' : 'disabled'}>중앙 저장소 → 세 모델</button><button class="btn btn-ghost" data-view-open="skill" data-view-name="${esc(name)}" data-view-scope="${esc(mxScopeOf('skill', name))}">내용 보기</button><button class="btn btn-ghost" data-tag-kind="skill" data-tag-id="${esc(name)}">태그 수정</button><button class="btn btn-ghost" id="panel-cancel">닫기</button>`,
  });
}

