840	async function copyToClipboard(text) {
841	  try {
842	    if (navigator.clipboard && navigator.clipboard.writeText) {
843	      await navigator.clipboard.writeText(text);
844	      return true;
845	    }
846	  } catch { /* 폴백으로 넘어감 */ }
847	  // 폴백: 화면 밖 textarea + execCommand('copy').
848	  try {
849	    const ta = document.createElement('textarea');
850	    ta.value = text;
851	    ta.setAttribute('readonly', '');
852	    ta.style.position = 'fixed';
853	    ta.style.top = '-9999px';
854	    document.body.appendChild(ta);
855	    ta.select();
856	    const ok = document.execCommand('copy');
857	    document.body.removeChild(ta);
858	    return ok;
859	  } catch { return false; }
860	}
